head.script:
scwin.p_clntNo;
scwin.p_clntNm;
scwin.p_airexgbim;
scwin.p_linkType;
scwin.p_kcomcd;
scwin.p_blno;
scwin.p_avdt;
scwin.p_dscd;
scwin.p_dsnm;
scwin.p_fltno;

//--------------------------------------------------------------------------//
//							메세지 상수 선언									//
//--------------------------------------------------------------------------//
scwin.MSG_LO_WRN_001 = "Consol 된 House 가 존재하여  삭제 불가능 합니다.";
scwin.MSG_LO_WRN_002 = "해당 B/L 번호로 복사 하시겠습니까?";

//--------------------------------------------------------------------------//
scwin.processFlag = "";  // 처리 결과를 체크하는 Flag 	
scwin.actionFlag = "";  // 버튼 Action 체크 Flag

//전역변수-페이지 링크로 들어 왔을때 해당 b/l, CONSOL 번호  조회 여부 체크
scwin.linkType = 0;
//---------------------------------------------------------
// 전역변수
//---------------------------------------------------------   
scwin.onpageload = function () {
    let memJson = $c.data.getMemInfo();
    // console.log("### onpageload :: " + JSON.stringify(memJson));
    scwin.p_airexgbim = memJson["airexgbim"];
    lc_shipgb.setSelectedIndex(-1);

    const resData = $c.gus.dsCommonUtil('getCompanyInfoDTO', memJson.lobranCd)[0].value.split('\n');

    const commDTO = resData.reduce((acc, curr) => {
        const match = curr.match(/^\s*\w+\s+(\w+)\s+=\s+\[(.*)\]/);

        if (match) {
            const key = match[1];
            let value = match[2];

            if (value == 'null') value = null;
            acc[key] = value;
        };
        return acc;

    }, {});
    scwin.p_clntNo = commDTO.clntNo || "null";
    scwin.p_clntNm = commDTO.name1 || "null";
    ed_blno.focus();
};

//---------------------------------------------------------
// UDC
//---------------------------------------------------------    
scwin.onUdcCompleted = function () {
    param = $c.data.getParameter();
    scwin.cvsslMgntNo = $c.util.isEmpty($c.data.getParameter("cvsslMgntNo")) ? "" : request.getParameter("cvsslMgntNo");
    scwin.p_kcomcd = $c.data.getParameter("kcomcd") || "DBEX";
    scwin.p_blno = $c.data.getParameter("blno");

    scwin.p_linkType = $c.data.getParameter("linkType");
    scwin.p_avdt = $c.data.getParameter("avdt"); //출발일 
    scwin.p_dscd = $c.data.getParameter("dscd"); //출발지 
    scwin.p_dsnm = $c.data.getParameter("dsnm"); //출발지 
    scwin.p_fltno = $c.data.getParameter("fltno"); //Flight No
    scwin.f_Set("INIT");
    scwin.f_getParametrSetting(); // link처리	  
}

//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------   
scwin.setRow = function (d, fd, r, c) {
    return (r + 1).toLocaleString();
}

scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            tb_1.setDisabled(true);
            tb_2.setDisabled(true);
            tb_3.setDisabled(true);
            tb_4.setDisabled(true);
            tb_7.setDisabled(true);
            $c.gus.cfDisableBtnOnly([btn_update, btn_save, btn_delete, btn_cancel]);
            $c.gus.cfDisableBtnOnly([btn_copy, btn_Bs, btn_Mnf]);
            $c.gus.cfEnableBtnOnly([btn_create, btn_find]);
            scwin.f_DisablePopUpObj();
            // gr_HouseBillInfo.Enable = true;
            //Key Enable
            $c.gus.cfEnableObjects([ed_blno, lc_mmhno]);
            break;
        case "RETRIEVE":  //조회모드	
            tb_1.setDisabled(true);
            tb_2.setDisabled(true);
            tb_3.setDisabled(true);
            tb_4.setDisabled(true);
            tb_7.setDisabled(true);
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_create, btn_update, btn_delete]);
            $c.gus.cfEnableBtnOnly([btn_copy, btn_find, btn_Bs, btn_Mnf]);
            // gr_HouseBillInfo.Enable = true;
            //Key Enable
            $c.gus.cfEnableObjects([ed_blno, lc_mmhno]);
            break;
        case "CREATE": //신규
            // $c.gus.cfEnableKeyData();
            tb_1.setDisabled(false);
            tb_2.setDisabled(false);
            tb_3.setDisabled(false);
            tb_4.setDisabled(false);
            tb_7.setDisabled(false);
            ed_arInv.setDisabled(true);
            ed_arHp.setDisabled(true);
            ed_arTax.setDisabled(true);
            ed_arTaxAmount.setDisabled(true);
            ed_updid.setDisabled(true);
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_create, btn_update, btn_delete]);
            $c.gus.cfEnableBtnOnly([btn_save, btn_cancel]);
            // gr_HouseBillInfo.Enable = true;
            //Key Enable
            $c.gus.cfEnableObjects([ed_blno, lc_mmhno]);
            break;
        case "UPDATE":
            tb_1.setDisabled(false);
            tb_2.setDisabled(false);
            tb_3.setDisabled(false);
            tb_4.setDisabled(false);
            tb_7.setDisabled(false);
            rd_cgtp.setDisabled(true);
            ed_arInv.setDisabled(true);
            ed_arHp.setDisabled(true);
            ed_arTax.setDisabled(true);
            ed_arTaxAmount.setDisabled(true);
            rd_frpc.setDisabled(true);
            ed_updid.setDisabled(true);
            $c.gus.cfDisableBtnOnly([btn_update, btn_create]);
            $c.gus.cfEnableBtnOnly([btn_save, btn_delete, btn_cancel]);
            // gr_HouseBillInfo.Enable = true;
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            //Key Disable
            $c.gus.cfDisableObjects([ed_blno, lc_mmhno]);
            break;
        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_update, btn_create, btn_delete]);
            scwin.f_Set("RETRIEVE");
            break;
        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_save, btn_cancel]);
            $c.gus.cfEnableBtnOnly([btn_create, btn_update, btn_delete]);
            scwin.f_Set("RETRIEVE");
            break;
    }
}

scwin.f_EnablePopUpObj = function () {
    // $c.gus.cfEnableObjects([img_ondt, img_avdt, img_ondt2, img_exdt]);
    $c.gus.cfEnableObjects([img_shcd, img_cacd, img_cncd, img_ntcd, img_dpcd]);
    $c.gus.cfEnableObjects([img_dscd1, img_dscd2, img_warecd]);
}

scwin.f_DisablePopUpObj = function () {
    // $c.gus.cfDisableObjects([img_ondt, img_avdt, img_ondt2, img_exdt]);
    $c.gus.cfDisableObjects([img_shcd, img_cacd, img_cncd, img_ntcd, img_dpcd]);
    $c.gus.cfDisableObjects([img_dscd1, img_dscd2, img_warecd]);
}

scwin.f_getParametrSetting = function () {
    var kcomcd = scwin.p_kcomcd;
    var blno = scwin.p_blno;

    var p_linkType = scwin.p_linkType;
    var ondt = scwin.p_avdt;
    var dscd = scwin.p_dscd;
    var dsnm = scwin.p_dsnm;
    var fltno = scwin.p_fltno;
    debugger;
    if ($c.util.isEmpty(blno)) {
        if (p_linkType == "MawbCreate") {
            scwin.f_Create();

            if (scwin.actionFlag == "Create") {
                ed_avdt.setValue(ondt);
                ed_dpcd.setValue(dscd);
                ed_exdt.setValue("");
                lc_exgb.setSelectedIndex(0);
                if (ed_dpcd.getValue() != '') {
                    scwin.f_PopUp("Departure", "T", "F", "F");
                }
                //txt_dpnm.value  = dsnm;

                ed_fltno.setValue(fltno);
            }
        }
        return false;
    }

    // hd_kcomcd.setValue(kcomcd);
    ed_blno.setValue(blno);

    scwin.linkType = 1;

    scwin.f_MhnoLoading();
    if ($c.util.isEmpty(scwin.p_blno) == false) scwin.f_Retrieve();
}

scwin.f_Create = function () {
    ds_MasterBillInfo.setEmptyValue();
    scwin.f_DefaultValue("Create");
    scwin.f_Set("CREATE");
    scwin.actionFlag = "Create";
    ed_blno.focus();
}

scwin.f_Update = function () {
    scwin.actionFlag = "Update";
    scwin.f_Set("UPDATE");
}

scwin.f_save = async function () {
    ds_MasterBillInfoList.setJSON([]);
    rowStatus = "";
    if (scwin.actionFlag == "Create" || scwin.actionFlag == "Copy") {
        if (!$c.util.isEmpty(lc_mmhno.getValue())) {
            //await $c.win.alert(ed_blno.getValue() + " 은(는) 중복될 수 없습니다.");  //
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, [ed_blno.getValue()]);
            ed_blno.focus();
            return false;
        }
        rowStatus = "C";
    }
    scwin.f_OtherTypeSetting();

    if (ds_MasterBillInfo.getModifiedIndex().length > 0) {
        scwin.f_ProcessBinding(ds_MasterBillInfo, "MasterBillSave");

        let checkFlag = await scwin.f_ReqFieldChk();
        if (checkFlag) {

            scwin.actionFlag = "Save";
            if (rowStatus != "C") rowStatus = "U";
            ds_MasterBillInfoList.setRowJSON(0, ds_MasterBillInfo.getJSON());
            ds_MasterBillInfoList.modifyRowStatus(0, rowStatus);

            await $c.sbm.execute(sbm_save);
            scwin.f_Set("SAVE");
            await $c.gus.cfAlertMsg("Data was saved successfully.");	// 성공적으로 저장하였습니다 	
            scwin.f_Retrieve();
        }
    } else {
        //await $c.win.alert("Master B/L Info 은(는) 변경된 사항이 없습니다.");  /* Master B/L Info 은(는) 변경된 사항이 없습니다. */
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Master B/L Info"]);  /* @은(는) 변경된 사항이 없습니다. */
        return false;
    }
}

scwin.f_ReqFieldChk = async function () {
    if (ed_blno.getValue() == "") {
        await $c.gus.cfAlertMsg("Master B/L No is mandatory.");  // @은(는) 필수 입력 항목 입니다.
        ed_blno.focus();
        return false;
    }
    if (ed_avdt.getValue() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["Arrival Date"]);  //필수 입력 항목입니다.
        ed_avdt.focus();
        return false;
    }
    if (await $c.gus.cfValidate([tbl_MasterBillInfo], null, true) == false) {
        return false;
    }
    return true;
}
scwin.f_Delete = async function () {
    if (ds_HouseBillInfo.getTotalRow() > 0) {
        await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_001);  //Consol 된 House 가 존재하여  삭제 불가능 합니다.
        ed_blno.focus();
        return false;
    }
    if (await $c.win.confirm(MSG_CM_CRM_004)) { //삭제 하시겠습니까? 
        ds_MasterBillInfoList.setJSON([]);
        ds_MasterBillInfoList.setRowJSON(0, ds_MasterBillInfo.getJSON());
        ds_MasterBillInfoList.modifyRowStatus(0, "D");
        scwin.actionFlag = "Delete";
        await $c.sbm.execute(sbm_save);
        scwin.f_ProcessResult("DeleteAction");
        await $c.gus.cfAlertMsg(MSG_CM_INF_004);	// 성공적으로 삭제하였습니다 		
    }
}

scwin.f_OtherTypeSetting = function () {
    var otpc_value = "";
    if (chb_otpc1.getValue() == "PP") {
        otpc_value = "PP";
    }
    if (chb_otpc2.getValue() == "CC") {
        otpc_value = "CC";
    }
    if ((chb_otpc1.getValue() == "PP") && (chb_otpc2.getValue() == "CC")) {
        otpc_value = "PC";
    }

    ds_MasterBillInfoList.setCellData(0, "otpc", otpc_value);
}

scwin.f_OtherTypeGetting = function () {
    otpc = hd_otpc.getValue();
    if (otpc == "PP") {
        chb_otpc1.setValue(otpc);
    }
    if (otpc == "CC") {
        chb_otpc2.setValue(otpc);
    }
    if (otpc == "PC") {
        chb_otpc1.setValue(otpc);
        chb_otpc2.setValue(otpc);
    }
}

scwin.f_Retrieve = function () {
    if (ed_blno.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["Master B/L No"]);  //필수 입력 항목 입니다.
        ed_blno.focus();
        return false;
    }
    ds_MasterBillInfo.setEmptyValue();
    ds_MasterBillInfoList.removeAll();
    ds_HouseBillInfo.removeAll();
    scwin.f_ProcessBinding(ds_SearchInfo, "SearchInfo");
    $c.sbm.execute(sbm_retrieve);
}

scwin.f_ProcessBinding = function (ds, gubun) {
    switch (gubun) {
        case "SearchInfo":
            // ds.setEmptyValue();
            ds.set("kcomcd", scwin.p_kcomcd);
            ds.set("blno", ed_blno.getValue());
            ds.set("mhno", lc_mmhno.getValue());
            ds.set("iogb", "I");
            break;
        case "MasterBillSave":
            ds.set("kcomcd", scwin.p_kcomcd);
            ds.set("iogb", "I");
            ds.set("blno", ed_blno.getValue());
            break;
        default:
            break;
    }  //end switch
}

scwin.f_FieldClear = function () {
    ds_SearchInfo.setEmptyValue();
    lc_mmhno.removeAll();
}

scwin.f_MhnoLoading = function () {
    var strClntNo = "";
    strClntNo = ed_blno.getValue();
    if (strClntNo.length > 0) {
        ds_mhno.set("sysCd", "ilCommonEBC");
        ds_mhno.set("queryId", "retriveAirMasterMhnoListCombo");
        ds_mhno.set("param1", strClntNo);
        ds_mhno.set("param2", "I");
        sbm_mhno.processMsg = "";
        $c.sbm.execute(sbm_mhno);
    } else {
        lc_mmhno.removeAll();
    }
}

scwin.f_ExrateLoading = function (param1, param2, param3) {
    if (param1.length > 0) {
        ds_ExRate.set("sysCd", "ilCommonEBC");
        ds_ExRate.set("queryId", "retrieveExRate");
        ds_ExRate.set("param1", param1);
        ds_ExRate.set("param2", param2);
        ds_ExRate.set("param3", param3);
        sbm_rate.processMsg = "";
        $c.sbm.execute(sbm_rate);
    }
}

scwin.f_DefaultValue = function (gubun) {
    debugger;
    switch (gubun) {
        case "Create":
            if (lc_mmhno.getValue() != "") {
                ed_blno.setValue("");
            }

            //default 동부국제물류
            ed_cncd.setValue(scwin.p_clntNo);
            txt_cnnm1.setValue(scwin.p_clntNm);

            ds_mhno.setEmptyValue();  // Consol No Clear

            lc_shipgb.setValue("C");
            ed_kggb.setValue("KG");
            rd_cgtp.setValue("N");
            ed_mftpkg.setValue("0");
            ed_mftwht.setValue("0");
            ed_rqrt.setValue("0");
            ed_tcwht.setValue("0");
            ed_cwht2.setValue("0");
            ed_cbm.setValue("0");
            lc_exgb.setValue(scwin.airexgbim);
            lc_shipgb.setSelectedIndex(0);
            ed_dscd1.setValue("ICN");
            scwin.f_PopUp("Destination", "T", "F", "F");
            rd_frpc.setValue("PP");
            chb_otpc1.setValue("");
            chb_otpc2.setValue("");
            break;
        case "Copy":
            ed_blno.setValue("");
            lc_mmhno.initAutoComplete();
            break;
        default:
            break;
    }
}

scwin.f_PopUp = function (disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (disGubun) {
        case "Shipper":		//거래처 팝업(Search Shipper)
            udc_sh.setSelectId("retrieveEngClntInfo");
            udc_sh.ilCommonPopUp(scwin.udc_sh_callbackFunc,
                ed_shcd.getValue(),           // 화면에서의 ??? Code Element의	Value                                  
                txt_shnm1.getValue(),                // 화면에서의 ??? Name Element의	Value                                  
                pWinCloseTF,                   // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                '6',                           // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                'Shipper',                     // Title순서	                                                           
                '130,300',                     // 보여주는 각 컬럼들의 폭	                                               
                null,                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                null,                          // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                '500',                         // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                '500',                         // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                null,                          // 윈도우 위치 Y좌표	                                                   
                null,                          // 윈도우 위치 X좌표                                                       
                null,                          // 중복체크여부	("F")                                                      
                pAllSearchTF,                  // 전체검색허용여부	("F")                                                  
                null,						   // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
                pNoDataCloseTF);
            break;
        case "Consignee":		//Search Consignee
            udc_cn.setSelectId("retrieveEngClntInfo");
            udc_cn.ilCommonPopUp(scwin.udc_cn_callbackFunc,
                ed_cncd.getValue(),
                txt_cnnm1.getValue(),
                pWinCloseTF,
                '6',
                'Consignee', '130,300',
                null, null,
                '500', '500',
                null, null, null,
                pAllSearchTF,
                null,
                pNoDataCloseTF);
            break;
        case "ColoadAgent":		//Search Co-Load Agent
            udc_nt.setSelectId("retrieveEngClntInfo");
            udc_nt.ilCommonPopUp(scwin.udc_nt_callbackFunc,
                ed_ntcd.getValue(),
                txt_ntnm1.getValue(),
                pWinCloseTF,
                '6',
                'Consignee', '130,300',
                null, null,
                '500', '500',
                null, null, null,
                pAllSearchTF,
                null,
                pNoDataCloseTF);
            break;
        case "Carrier":		//Search Carrier
            udc_ca.setSelectId("retrieveEngCarrInfo");
            udc_ca.ilCommonPopUp(scwin.udc_ca_callbackFunc,
                ed_cacd.getValue(),
                txt_canm.getValue(),
                pWinCloseTF,
                '2',
                'Carrier',
                '130,300',
                "3,4,5,6,7,8,9,10",
                null,
                '500', '500',
                null, null, null,
                pAllSearchTF,
                null,
                pNoDataCloseTF);
            break;
        case "Departure":		//Search Departure
            udc_dp.setSelectId("retrieveAirPortCode");
            udc_dp.ilCommonPopUp(scwin.udc_dp_callbackFunc,
                ed_dpcd.getValue(),
                txt_dpnm.getValue(),
                pWinCloseTF,
                '6',
                'Port Code, Port Name',
                '130,300',
                "3,4,5,7,8,9,10",
                null,
                '500', '500',
                null, null, null,
                pAllSearchTF,
                'Departure Search, Port Code, Port Name',
                pNoDataCloseTF);
            break;
        case "ViaPort":		//Search VIA Port
            udc_ds2.setSelectId("retrieveAirPortCode");
            udc_ds2.ilCommonPopUp(scwin.udc_ds2_callbackFunc,
                ed_dscd2.getValue(),
                txt_dsnm2.getValue(),
                pWinCloseTF,
                '2',
                'Port Code, Port Name',
                '130,300',
                "3,4,5,6,7,8,9,10",
                null,
                '500', '500',
                null, null, null,
                pAllSearchTF,
                'VIA Port Search, Port Code, Port Name',
                pNoDataCloseTF);
            break;
        case "Destination":		//Search Destination
            udc_ds1.setSelectId("retrieveAirPortCode");
            udc_ds1.ilCommonPopUp(scwin.udc_ds1_callbackFunc, ed_dscd1.getValue(), txt_dsnm1.getValue(), pWinCloseTF, '2', 'Port Code, Port Name', '130,300', "3,4,5,6,7,8,9,10", null, '500', '500', null, null, null, pAllSearchTF, 'Destination Search, Port Code, Port Name', pNoDataCloseTF);
            break;
        default:
            break;
    }
}

//공통팝업 열기
scwin.f_OpenCommonPopUp = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {

    switch (gubun1) {
        case "Warehouse":  //Warehouse
            udc_ware.setSelectId("retrieveAirBoneZoneCode");
            udc_ware.ilCommonPopUp(scwin.udc_ware_callbackFunc
                , ed_warecd.getValue()	// 화면에서의 ??? Code Element의	Value
                , txt_warenm.getValue()		// 화면에서의 ??? Name Element의	Value
                , pWinCloseTF			// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , '4'			        // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , "Code, Name,'',Eng"           // Title순서	
                , '80,200,0,60'				// 보여주는 각 컬럼들의 폭	
                , "3,5,6,7,8,9,10"	    // 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , pAllSearchTF			// 전체검색허용여부	("F")
                , "Warehouse,Code,Name"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                , pNoDataCloseTF         // Data 건수가 0 일때 Window를 뛰우지 않음 리턴 : "N/A"
            );
            break;
        default:
            break;
    }
}

