scwin.f_copy = async function () {
    if (await $c.win.confirm(scwin.MSG_LO_WRN_002)) { 	//해당 B/L 번호로 복사 하시겠습니까?   	
        scwin.actionFlag = "Copy";
        scwin.f_DefaultValue("Copy");
        scwin.f_Set("CREATE");
        ed_blno.focus();
    }
}

scwin.f_cancel = function () {
    if (scwin.actionFlag == "Create") {
        scwin.f_Set("INIT");
        scwin.processFlag = "None";
    } else {
        scwin.f_Set("RETRIEVE");
    }
    // ds_MasterBillInfo.undo();
    tb_1.setDisabled(true);
    tb_2.setDisabled(true);
}

scwin.f_Create = function () {
    ds_MasterBillInfo.setEmptyValue();
    ds_HouseBillInfo.removeAll();
    scwin.f_DefaultValue("Create");
    scwin.f_Set("CREATE");
    scwin.actionFlag = "Create";
    ed_blno.focus();
}

scwin.f_ProcessResult = function (gubun) {
    switch (gubun) {
        case "NotExistMasterInfo":
            scwin.f_Set("INIT");
            ds_HouseBillInfo.setJSON([]);
            $c.gus.cfAlertMsg(MSG_CM_ERR_049, [ed_blno.getValue()]);  //@이(가) 존재하지 않습니다.
            ed_blno.focus();
            break;
        case "ExistMasterInfo":
            scwin.f_OtherTypeGetting();
            scwin.f_Set("RETRIEVE");
            ed_blno.focus();
            break;
        case "DeleteAction":
            ds_MasterBillInfo.setEmptyValue();
            ds_HouseBillInfo.setJSON([])
            ed_blno.setValue("");
            lc_mmhno.removeAll();
            ed_blno.focus();
            break;
        default:
            break;
    }
}

scwin.f_openPgm = function (name) {
    title = "";
    path = "";
    menuId = "";
    param = {};
    if (name == "Find") {
        title = "Master B/L Search";
        path = "/il/airout/aobl/ar_103_01_02b";
        menuId = "ar_103_01_02b";
        param = {
            iogb: "I"
        }
    } else if (name == "HAWB") {
        title = "Import House B/L";
        path = "/il/airinb/aibl/ar_203_01_01b";
        menuId = "ar_203_01_01b";
        param = {
            kcomcd: scwin.p_kcomcd
            , mblno: ed_blno.getValue()
            , dpcd: ed_dpcd.getValue()
            , dpnm: txt_dpnm.getValue()
            , type: "HawbCreate"
        }
    } else if (name == "PL") {
        title = "Booking Sheet";
        path = "/il/pfm/pfbs/pe_101_01_01b";
        menuId = "pe_101_01_01b";
        param = {
            kcomcd: scwin.p_kcomcd
            , seaair: "A"
            , iogb: "I"
            , blno: ""
            , mblno: ed_blno.getValue()
            , mhno: lc_mmhno.getValue()
        }
    } else if (name == "MNF") {
        title = "Cargo Manifest";
        path = "/il/airout/aoth/ar_105_01_01b";
        menuId = "ar_105_01_01b";
        param = {
            kcomcd: scwin.p_kcomcd
            , iogb: "I"
            , blno: ed_blno.getValue()
            , mhno: lc_mmhno.getValue()
        }
    }

    $c.win.openMenu(title, "/ui" + path + ".xml", menuId, param || {}, { openAction: "exist" });
}

scwin.f_HouseLink = function () {
    menuNm = "";
    src = "";
    menuId = "ar_203_01_01b";

    paramObj = {};

    src = "/ui/il/airinb/aibl/ar_203_01_01b.xml";
    menuNm = "Import House B/L";

    paramObj = {
        kcomcd: scwin.p_kcomcd
        , blno: ds_HouseBillInfo.getCellData(ds_HouseBillInfo.getRowPosition(), "blno")
    };

    $c.win.openMenu(menuNm, src, menuId, paramObj);
}
