scwin.sbm_retrieve_submitdone = function (e) {
    if (ds_MasterBillInfoList.getTotalRow() == 0) {
        scwin.f_Set("INIT");
        ds_HouseBillInfo.removeAll();
        $c.gus.cfAlertMsg(MSG_CM_ERR_049, [ed_blno.getValue()]);  //@이(가) 존재하지 않습니다.
        ed_blno.focus();
    } else {
        ed_totCnt.setValue(ds_HouseBillInfo.getTotalRow());
        ds_MasterBillInfo.setJSON(ds_MasterBillInfoList.getRowJSON(0));
        scwin.f_OtherTypeGetting();
        scwin.f_Set("RETRIEVE");
        ed_blno.focus();
    }
}
