            ed_cwht2.setValue(Number(strClntNo) / 0.45359);
        }

        if (ed_cbm.getValue() == 0 || ed_cbm.getValue() == "") {
            ed_cbm.setValue(Number(strClntNo) / 166.66);
        }

    }
};

